export default {
  name: 'DashboardCheckbox',
  props: {
    checked: {
      type: Boolean,
      default: false
    },
    indeterminate: {
      type: Boolean,
      default: false
    },
    variant: {
      type: String,
      default: 'breadcrumb',
      validator: value => ['breadcrumb'].includes(value)
    }
  },
  emits: ['click'],
  computed: {
    ariaChecked() {
      if (this.checked) return 'true';
      if (this.indeterminate) return 'mixed';
      return 'false';
    },
    markIcon() {
      return this.indeterminate && !this.checked ? 'minus' : 'check';
    }
  },
  methods: {
    handleClick(event) {
      this.$emit('click', event);
    }
  }
};