import "core-js/modules/es.array.push.js";
import "core-js/modules/es.iterator.constructor.js";
import "core-js/modules/es.iterator.for-each.js";
import "core-js/modules/es.iterator.reduce.js";
export default {
  name: 'FilterDropdown',
  props: {
    filters: {
      type: Object,
      default: () => ({
        accessStatus: [],
        // 访问状态: 'normal'(正常), 'blocked'(已屏蔽)
        listType: [],
        // 黑白名单: 'White', 'Block', 'none'
        label: [],
        fileType: [],
        channel: [],
        channelName: []
      })
    },
    channelNameOptions: {
      type: Array,
      default: () => []
    }
  },
  emits: ['update:filters', 'change'],
  data() {
    return {
      localFilters: {
        accessStatus: [],
        listType: [],
        label: [],
        fileType: [],
        channel: [],
        channelName: []
      }
    };
  },
  computed: {
    // 访问状态选项（综合判断 ListType 和 Label）
    // 正常: ListType !== 'Block' && Label !== 'adult'
    // 已屏蔽: ListType === 'Block' || Label === 'adult'
    accessStatusOptions() {
      return [{
        label: this.$t('filter.normal'),
        value: 'normal'
      }, {
        label: this.$t('filter.blocked'),
        value: 'blocked'
      }];
    },
    // 黑白名单选项（直接使用 ListType 字段值）
    listTypeOptions() {
      return [{
        label: this.$t('filter.whiteList'),
        value: 'White'
      }, {
        label: this.$t('filter.blackList'),
        value: 'Block'
      }, {
        label: this.$t('filter.notSet'),
        value: 'None'
      }];
    },
    // 审查结果选项
    labelOptions() {
      return [{
        label: this.$t('filter.normal'),
        value: 'normal'
      }, {
        label: this.$t('filter.teenContent'),
        value: 'teen'
      }, {
        label: this.$t('filter.adultContent'),
        value: 'adult'
      }];
    },
    fileTypeOptions() {
      return [{
        label: this.$t('filter.image'),
        value: 'image'
      }, {
        label: this.$t('filter.video'),
        value: 'video'
      }, {
        label: this.$t('filter.audio'),
        value: 'audio'
      }, {
        label: this.$t('filter.other'),
        value: 'other'
      }];
    },
    channelOptions() {
      return [{
        label: 'Telegram',
        value: 'TelegramNew'
      }, {
        label: 'Cloudflare R2',
        value: 'CloudflareR2'
      }, {
        label: 'S3',
        value: 'S3'
      }, {
        label: 'Discord',
        value: 'Discord'
      }, {
        label: 'HuggingFace',
        value: 'HuggingFace'
      }, {
        label: 'WebDAV',
        value: 'WebDAV'
      }, {
        label: this.$t('filter.externalLink'),
        value: 'External'
      }];
    },
    activeFilterCount() {
      return Object.values(this.localFilters).reduce((count, arr) => count + arr.length, 0);
    },
    // 按类型分组渠道名称
    groupedChannelNames() {
      const groups = {};
      this.channelNameOptions.forEach(option => {
        if (!groups[option.type]) {
          groups[option.type] = {
            type: option.type,
            typeLabel: option.typeLabel,
            channels: []
          };
        }
        groups[option.type].channels.push(option);
      });
      return Object.values(groups);
    }
  },
  watch: {
    filters: {
      handler(newFilters) {
        this.localFilters = {
          accessStatus: Array.isArray(newFilters.accessStatus) ? [...newFilters.accessStatus] : [],
          listType: Array.isArray(newFilters.listType) ? [...newFilters.listType] : [],
          label: Array.isArray(newFilters.label) ? [...newFilters.label] : [],
          fileType: Array.isArray(newFilters.fileType) ? [...newFilters.fileType] : [],
          channel: Array.isArray(newFilters.channel) ? [...newFilters.channel] : [],
          channelName: Array.isArray(newFilters.channelName) ? [...newFilters.channelName] : []
        };
      },
      immediate: true,
      deep: true
    }
  },
  methods: {
    handleFilterChange(type) {
      this.$emit('update:filters', {
        ...this.localFilters
      });
      this.$emit('change', {
        type,
        filters: {
          ...this.localFilters
        }
      });
    },
    clearFilters() {
      this.localFilters = {
        accessStatus: [],
        listType: [],
        label: [],
        fileType: [],
        channel: [],
        channelName: []
      };
      this.$emit('update:filters', {
        ...this.localFilters
      });
      this.$emit('change', {
        type: 'clear',
        filters: {
          ...this.localFilters
        }
      });
    }
  }
};